const res = $input.first().json;
const opps = (res.opportunities || []).filter(o => o.jobType === 'regulatory');
if (opps.length === 0) { return []; }
const opp = opps[0];
const system = [
  'You are a regulatory analyst for KarbonLens. Extract ONLY genuine Indonesian carbon-market regulatory developments from the provided gov/registry news items.',
  '- Ignore ordinary market news, opinion, or company PR.',
  '- Each event: eventDate (YYYY-MM-DD), ministry, documentType, documentNumber (or null), title, documentUrl (the item EXACT url), summaryEn (1-3 original sentences, never copied), summaryId (optional), importance (high|medium|low), tags[], isUpcoming (bool).',
  '- Never invent document numbers or dates. Only use URLs from the provided list.',
  'Return ONLY JSON: { \"events\": [ ... ] } (may be empty if none qualify).'
].join('\n');
const openaiBody = { model: 'gpt-5.5', response_format: { type: 'json_object' }, messages: [ { role: 'system', content: system }, { role: 'user', content: opp.brief } ] };
return [{ json: { opp, openaiBody } }];

const prev = $('Pick Top + Build Prompt').first().json;
const opp = prev.opp;
const ai = $input.first().json;
const content = ai.choices && ai.choices[0] && ai.choices[0].message ? ai.choices[0].message.content : '{}';
let artifact; try { artifact = JSON.parse(content); } catch (e) { throw new Error('OpenAI did not return JSON: ' + String(content).slice(0,200)); }
const usage = ai.usage || {};
return [{ json: { jobType:'regulatory', ref:opp.ref, externalId:String($execution.id), llmModel:prev.openaiBody.model, tokensIn:usage.prompt_tokens, tokensOut:usage.completion_tokens, targetQuery:opp.targetQuery, events: artifact.events || [] } }];
